import "../shared/index.tsp";
namespace MyDomain;

@friendlyName("MyResource")
model MyResource {
  ...Shared.ResourceWithKey;
  @visibility(Lifecycle.Read, Lifecycle.Create, Lifecycle.Update)
  @summary("Status")
  status: MyStatus;
}
interface MyResourceOperations {
  @post @operationId("create-my-resource") create(@body body: Shared.CreateRequest<MyResource>): Shared.CreateResponse<MyResource>;
}

// In operations.tsp, inside interface SubscriptionsOperations:
@post @operationId("pause-subscription") @summary("Pause subscription")
@route("/{subscriptionId}/pause")
pause(@path subscriptionId: Shared.ULID, @body body: SubscriptionPause):
  | Shared.UpdateResponse<Subscription>
  | Common.NotFound | Common.Conflict | Common.ErrorResponses;

// In codes.tsp:
model TaxCode {
  ...Shared.ResourceWithKey;
  @visibility(Lifecycle.Read, Lifecycle.Create, Lifecycle.Update)
  @summary("Category")
  category?: string;
  @visibility(Lifecycle.Read, Lifecycle.Update, Lifecycle.Create)
  @summary("App type to tax code mappings")
  app_mappings: TaxCodeAppMapping[];
}
